package main

import "fmt"

type FileEvidence struct {
	FileID      string
	ObjectKey   string
	VersionID   string
	Bytes       int
	Checksum    string
}

type DeliveryEvidence struct {
	Authorized bool
	State      string
	RangeStart int
	RangeEnd   int
}

func main() { fmt.Println("Go file-delivery portfolio ready") }

